import React from 'react';
import { SmartSearch } from './SmartSearch';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Smart Search</h1>
      <SmartSearch apiUrl="/api/search" debounceMs={300} cacheTtl={5000} />
    </div>
  );
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import './styles.css';

interface SearchResult {
  id: number;
  title: string;
}

interface LogEntry {
  requestId: number;
  query: string;
  status: 'pending' | 'success' | 'aborted' | 'cached' | 'stale';
  duration?: number;
}

interface SmartSearchProps {
  apiUrl: string;
  debounceMs: number;
  cacheTtl: number;
}

// TODO: Implement deduplication & race condition handling
// 1. Debounce input
// 2. Abort previous request on new one
// 3. Track request IDs to detect stale responses
// 4. Cache results for cacheTtl ms
// 5. Log each request lifecycle

export const SmartSearch: React.FC<SmartSearchProps> = ({ apiUrl, debounceMs, cacheTtl }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [log, setLog] = useState<LogEntry[]>([]);
  const [cacheStatus, setCacheStatus] = useState<'hit' | 'miss' | null>(null);
  const [activeCount, setActiveCount] = useState(0);
  // TODO: refs for AbortController, debounce timer, request counter, cache

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);
    // TODO: debounce and trigger search
  };

  return (
    <div className="ssearch">
      <input
        data-testid="search-input"
        className="ssearch__input"
        type="text"
        placeholder="Search…"
        value={query}
        onChange={handleInputChange}
      />

      <div className="ssearch__meta">
        {isLoading && <span data-testid="loading" className="ssearch__loading">Searching…</span>}
        <span data-testid="active-requests" className="ssearch__active">
          Active: {activeCount}
        </span>
        {cacheStatus && (
          <span data-testid="cache-indicator" className={`ssearch__cache ssearch__cache--${cacheStatus}`}>
            Cache {cacheStatus}
          </span>
        )}
      </div>

      <div data-testid="results-list" className="ssearch__results">
        {results.map((r, i) => (
          <div key={r.id} data-testid={`result-${i}`} className="ssearch__result">
            {r.title}
          </div>
        ))}
        {!isLoading && results.length === 0 && query && (
          <div className="ssearch__empty">No results</div>
        )}
      </div>

      <div data-testid="request-log" className="ssearch__log">
        <h3>Request Log</h3>
        {log.map((entry, i) => (
          <div key={i} data-testid={`log-${i}`} className={`ssearch__log-entry ssearch__log-entry--${entry.status}`}>
            #{entry.requestId} "{entry.query}" — {entry.status}
            {entry.duration !== undefined && ` (${entry.duration}ms)`}
          </div>
        ))}
      </div>
    </div>
  );
};

.ssearch {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.ssearch__input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  box-sizing: border-box;
}

.ssearch__input:focus {
  outline: none;
  border-color: #3b82f6;
  box-shadow: 0 0 0 2px rgba(59,130,246,0.15);
}

.ssearch__meta {
  display: flex;
  gap: 1rem;
  align-items: center;
  font-size: 0.8125rem;
}

.ssearch__loading {
  color: #3b82f6;
}

.ssearch__active {
  color: #6b7280;
}

.ssearch__cache {
  padding: 0.0625rem 0.375rem;
  border-radius: 9999px;
  font-size: 0.6875rem;
  font-weight: 500;
}

.ssearch__cache--hit { background: #dcfce7; color: #16a34a; }
.ssearch__cache--miss { background: #fef3c7; color: #d97706; }

.ssearch__results {
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  min-height: 4rem;
}

.ssearch__result {
  padding: 0.5rem 0.75rem;
  font-size: 0.875rem;
  border-bottom: 1px solid #f3f4f6;
}

.ssearch__result:last-child {
  border-bottom: none;
}

.ssearch__empty {
  padding: 1rem;
  text-align: center;
  color: #9ca3af;
  font-size: 0.8125rem;
}

.ssearch__log {
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  padding: 0.75rem;
}

.ssearch__log h3 {
  font-size: 0.8125rem;
  margin: 0 0 0.5rem;
  color: #374151;
}

.ssearch__log-entry {
  font-size: 0.75rem;
  padding: 0.125rem 0;
  font-family: monospace;
}

.ssearch__log-entry--success { color: #16a34a; }
.ssearch__log-entry--aborted { color: #9ca3af; text-decoration: line-through; }
.ssearch__log-entry--cached { color: #8b5cf6; }
.ssearch__log-entry--stale { color: #d97706; }
.ssearch__log-entry--pending { color: #6b7280; }

