import { render, screen, fireEvent, waitFor, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;

beforeEach(() => {
  jest.useFakeTimers();
  fetchMock = jest.fn((url: string, opts?: any) => {
    const params = new URL(url, 'http://localhost').searchParams;
    const q = params.get('q') || '';
    return new Promise((resolve, reject) => {
      if (opts?.signal) {
        opts.signal.addEventListener('abort', () => reject(new DOMException('Aborted', 'AbortError')));
      }
      setTimeout(() => {
        resolve({
          ok: true,
          json: () => Promise.resolve({
            results: [{ id: 1, title: `Result for "${q}"` }],
          }),
        });
      }, 100);
    });
  });
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.useRealTimers();
  jest.restoreAllMocks();
});

import App from './App';

describe('Request Deduplication & Race Conditions', () => {
  it('renders search input', () => {
    render(<App />);
    expect(screen.getByTestId('search-input')).toBeInTheDocument();
  });

  it('debounces input before searching', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'react' } });
    expect(fetchMock).not.toHaveBeenCalled();
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    expect(fetchMock).toHaveBeenCalled();
  });

  it('shows loading state during fetch', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'test' } });
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    expect(screen.getByTestId('loading')).toBeInTheDocument();
  });

  it('displays results after fetch completes', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'hello' } });
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    await act(async () => {
      jest.advanceTimersByTime(100);
    });
    await waitFor(() => {
      expect(screen.getByTestId('result-0')).toBeInTheDocument();
    });
  });

  it('aborts previous request on new input', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'ab' } });
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    // New search before first completes
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'abc' } });
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    // First should be aborted, second should proceed
    expect(fetchMock).toHaveBeenCalledTimes(2);
  });

  it('populates request log', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'log' } });
    await act(async () => {
      jest.advanceTimersByTime(300);
    });
    await act(async () => {
      jest.advanceTimersByTime(100);
    });
    await waitFor(() => {
      expect(screen.getByTestId('log-0')).toBeInTheDocument();
    });
  });

  it('shows cache indicator on duplicate query', async () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'dup' } });
    await act(async () => { jest.advanceTimersByTime(300); });
    await act(async () => { jest.advanceTimersByTime(100); });
    await waitFor(() => expect(screen.getByTestId('result-0')).toBeInTheDocument());
    const callsBefore = fetchMock.mock.calls.length;
    // Clear and retype same query
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: '' } });
    fireEvent.change(screen.getByTestId('search-input'), { target: { value: 'dup' } });
    await act(async () => { jest.advanceTimersByTime(300); });
    // Should use cache - no new fetch
    await waitFor(() => {
      expect(screen.getByTestId('cache-indicator')).toHaveTextContent(/hit/i);
    });
  });
});

