import React, { useState, useRef, useCallback, useEffect } from 'react';
import './styles.css';

interface SearchResult {
  id: number;
  title: string;
}

interface LogEntry {
  requestId: number;
  query: string;
  status: 'pending' | 'success' | 'aborted' | 'cached' | 'stale';
  duration?: number;
}

interface CacheEntry {
  data: SearchResult[];
  timestamp: number;
}

interface SmartSearchProps {
  apiUrl: string;
  debounceMs: number;
  cacheTtl: number;
}

export const SmartSearch: React.FC<SmartSearchProps> = ({ apiUrl, debounceMs, cacheTtl }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [log, setLog] = useState<LogEntry[]>([]);
  const [cacheStatus, setCacheStatus] = useState<'hit' | 'miss' | null>(null);
  const [activeCount, setActiveCount] = useState(0);

  const abortRef = useRef<AbortController | null>(null);
  const debounceRef = useRef<number | null>(null);
  const requestIdRef = useRef(0);
  const latestIdRef = useRef(0);
  const cacheRef = useRef<Map<string, CacheEntry>>(new Map());

  const addLog = useCallback((entry: LogEntry) => {
    setLog(prev => [...prev, entry]);
  }, []);

  const updateLog = useCallback((reqId: number, update: Partial<LogEntry>) => {
    setLog(prev => prev.map(e => e.requestId === reqId ? { ...e, ...update } : e));
  }, []);

  const doSearch = useCallback(async (q: string) => {
    if (!q.trim()) {
      setResults([]);
      setCacheStatus(null);
      return;
    }

    // Check cache
    const cached = cacheRef.current.get(q);
    if (cached && Date.now() - cached.timestamp < cacheTtl) {
      const reqId = ++requestIdRef.current;
      latestIdRef.current = reqId;
      setResults(cached.data);
      setCacheStatus('hit');
      addLog({ requestId: reqId, query: q, status: 'cached', duration: 0 });
      return;
    }

    setCacheStatus('miss');

    // Abort previous
    if (abortRef.current) {
      abortRef.current.abort();
    }

    const controller = new AbortController();
    abortRef.current = controller;

    const reqId = ++requestIdRef.current;
    latestIdRef.current = reqId;
    const startTime = Date.now();

    addLog({ requestId: reqId, query: q, status: 'pending' });
    setIsLoading(true);
    setActiveCount(prev => prev + 1);

    try {
      const res = await fetch(`${apiUrl}?q=${encodeURIComponent(q)}`, {
        signal: controller.signal,
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      const duration = Date.now() - startTime;

      // Check if still the latest request
      if (reqId === latestIdRef.current) {
        setResults(json.results);
        cacheRef.current.set(q, { data: json.results, timestamp: Date.now() });
        updateLog(reqId, { status: 'success', duration });
      } else {
        updateLog(reqId, { status: 'stale', duration });
      }
    } catch (err: any) {
      if (err.name === 'AbortError') {
        updateLog(reqId, { status: 'aborted', duration: Date.now() - startTime });
      } else {
        updateLog(reqId, { status: 'aborted', duration: Date.now() - startTime });
      }
    } finally {
      setActiveCount(prev => Math.max(0, prev - 1));
      if (reqId === latestIdRef.current) {
        setIsLoading(false);
      }
    }
  }, [apiUrl, cacheTtl, addLog, updateLog]);

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setQuery(value);

    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    debounceRef.current = window.setTimeout(() => {
      doSearch(value);
    }, debounceMs);
  }, [debounceMs, doSearch]);

  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
      abortRef.current?.abort();
    };
  }, []);

  return (
    <div className="ssearch">
      <input
        data-testid="search-input"
        className="ssearch__input"
        type="text"
        placeholder="Search…"
        value={query}
        onChange={handleInputChange}
      />

      <div className="ssearch__meta">
        {isLoading && <span data-testid="loading" className="ssearch__loading">Searching…</span>}
        <span data-testid="active-requests" className="ssearch__active">
          Active: {activeCount}
        </span>
        {cacheStatus && (
          <span data-testid="cache-indicator" className={`ssearch__cache ssearch__cache--${cacheStatus}`}>
            Cache {cacheStatus}
          </span>
        )}
      </div>

      <div data-testid="results-list" className="ssearch__results">
        {results.map((r, i) => (
          <div key={r.id} data-testid={`result-${i}`} className="ssearch__result">
            {r.title}
          </div>
        ))}
        {!isLoading && results.length === 0 && query && (
          <div className="ssearch__empty">No results</div>
        )}
      </div>

      <div data-testid="request-log" className="ssearch__log">
        <h3>Request Log</h3>
        {log.map((entry, i) => (
          <div key={i} data-testid={`log-${i}`} className={`ssearch__log-entry ssearch__log-entry--${entry.status}`}>
            #{entry.requestId} "{entry.query}" — {entry.status}
            {entry.duration !== undefined && ` (${entry.duration}ms)`}
          </div>
        ))}
      </div>
    </div>
  );
};
